<?php
declare(strict_types=1);require_once dirname(__DIR__,2).'/includes/comunicacion_layout.php';$pdo=obtenerConexion();$actor=(int)$_SESSION['usuario_id'];$vista=in_array($_GET['vista']??'',['entrada','enviados','no-leidos'],true)?$_GET['vista']:'entrada';$buscar=trim((string)($_GET['q']??''));$yo=comunicacionUsuario($pdo,$actor);$esAdmin=$_SESSION['usuario_rol']==='admin';$where=$vista==='enviados'?($esAdmin?"m.direccion='salida'":"m.direccion='salida' AND m.autor_usuario_id=:u"):($esAdmin?"m.direccion='entrada'":"m.direccion='entrada' AND (h.usuario_relacionado_id=:u OR m.destinatario=:correo)");$p=[];if(!$esAdmin)$p['u']=$actor;if($vista!=='enviados'&&!$esAdmin)$p['correo']=$yo['correo'];if($vista==='no-leidos')$where.=' AND m.leido_at IS NULL';if($buscar!==''){$where.=' AND (m.asunto LIKE :q1 OR m.contenido_texto LIKE :q2 OR m.remitente LIKE :q3 OR m.destinatario LIKE :q4)';$p['q1']=$p['q2']=$p['q3']=$p['q4']='%'.$buscar.'%';}$q=$pdo->prepare("SELECT m.*,h.asunto hilo_asunto,(SELECT COUNT(*) FROM correo_centro_adjuntos a WHERE a.mensaje_id=m.id) adjuntos FROM correo_centro_mensajes m JOIN correo_centro_hilos h ON h.id=m.hilo_id WHERE $where ORDER BY m.enviado_recibido_at DESC LIMIT 200");$q->execute($p);$mensajes=$q->fetchAll();$imap=configuracionImapAtenea();comunicacionCabecera($vista==='enviados'?'Correos enviados':'Bandeja de entrada',$vista,'Centro de correo institucional.');comunicacionNav($vista);?>
<?php if($vista!=='enviados'&&!imapAteneaConfigurado()):?><div class="alert alert-warning"><strong>IMAP pendiente de configuración.</strong> No se muestran correos simulados. Configura IMAP_HOST, IMAP_PORT, IMAP_ENCRYPTION, IMAP_USERNAME e IMAP_PASSWORD y habilita la extensión IMAP de PHP.</div><?php endif;?><div class="card card-rounded"><div class="card-body"><form class="mb-3"><input type="hidden" name="vista" value="<?=atenea_e($vista)?>"><input class="form-control" name="q" value="<?=atenea_e($buscar)?>" placeholder="Buscar por asunto, remitente o contenido"></form><div class="table-responsive"><table class="table"><thead><tr><th>Asunto</th><th><?=$vista==='enviados'?'Destinatario':'Remitente'?></th><th>Estado</th><th>Fecha</th><th></th></tr></thead><tbody><?php foreach($mensajes as$m):?><tr><td><?=atenea_e($m['asunto'])?><?=$m['adjuntos']?' 📎':''?><small class="d-block text-muted"><?=atenea_e(mb_strimwidth($m['contenido_texto'],0,100,'…'))?></small></td><td><?=atenea_e($vista==='enviados'?$m['destinatario']:$m['remitente'])?></td><td><?=atenea_e($m['estado'])?><?php if($m['error_sanitizado']):?><small class="d-block text-danger"><?=atenea_e($m['error_sanitizado'])?></small><?php endif;?></td><td><?=atenea_e($m['enviado_recibido_at'])?></td><td><a class="btn btn-sm btn-outline-primary" href="correo-hilo.php?id=<?=$m['hilo_id']?>">Ver hilo</a></td></tr><?php endforeach;?><?php if(!$mensajes):?><tr><td colspan="5" class="text-center py-5">No hay correos reales en esta vista.</td></tr><?php endif;?></tbody></table></div></div></div><?php comunicacionPie();
